var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으음...","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"앗... 여긴...?","JPN":"こ……ここは……？","ENG":"Huh...? Where am I...?","TWN":"咦……這裡是……？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이제 좀 괜찮아요?","JPN":"少しは楽になりましたか？","ENG":"Are you feeling a little better now?","TWN":"你現在覺得舒服點了嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"엄청 늦잠 잤네요.","JPN":"大寝坊ですよ。","ENG":"You really overslept.","TWN":"你睡得可真久呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...니콜?","JPN":"……ニコル？","ENG":"...Nicole?","TWN":"……妮可？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무서운 일이 있었도다. 이 몸이 못된 녀석한테 붙잡혀서...","JPN":"怖いことがあったのだ。吾輩が悪い奴に捕まって……","ENG":"A dreadful thing happened. I was captured by a wicked one...","TWN":"剛剛發生了很可怕的事，我被壞人抓走了……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"...영영 돌아오지 못할 뻔했었죠.","JPN":"……永遠に帰ってこられなくなるところでしたね。","ENG":"...You almost never made it back.","TWN":"……差點就永遠回不來了呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만 이제 걱정 말아요. 모모를 괴롭히던 못된 마왕은 이제 사라졌으니까.","JPN":"でももう心配しなくて大丈夫です。モモをいじめていた悪い魔王は消えましたから。","ENG":"But you don't have to worry anymore. The wicked Demon Lord who was tormenting you is gone now.","TWN":"不過現在不用擔心了，欺負莫莫的壞魔王已經不在了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그게 무슨 소리냐. 마왕은...","JPN":"何を言っている？　魔王は……","ENG":"What are you saying? I...","TWN":"那是什麼意思？魔王不是……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...마왕은, 바로 이 몸이지 않더냐.","JPN":"……魔王は、吾輩ではないか。","ENG":"...I am the Demon Lord.","TWN":"……魔王，不就是我嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"물론 모모는 마왕님이죠. 하지만 세상을 멸망시키려던 타기리온은 아녜요.","JPN":"もちろん、モモは魔王ですよ。でも世界を滅ぼそうとしていたタギリオンではありません。","ENG":"Of course you are, Momo. But you're not Thagirion, the one who tried to destroy the world.","TWN":"莫莫當然是魔王，但並不是那個想毀滅世界的塔基里翁。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 사람에게서 떨어져 나온 순수한 마음 중 하나였을 뿐이죠.","JPN":"彼女が持っていた、純粋な心の一つだっただけです。","ENG":"You were only one of the pure pieces of her heart.","TWN":"那只是她擁有的純真的一部分而已。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그치만 모모는...","JPN":"しかし、モモは……","ENG":"But Momo is...","TWN":"可是莫莫……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"...모드레드가 알고 있던 모르가나가 아닌걸.","JPN":"……モードレッドが知っていたモルガナではないぞ。","ENG":"...Not the Morgana that Mordred once knew.","TWN":"……並不是莫德雷認識的莫甘娜。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저도 모드레드가 아녜요. 니콜 프라이머죠.","JPN":"私はモードレッドじゃありません。ニコル・プライマーです。","ENG":"I'm not Mordred. I'm Nicole Primer.","TWN":"我不是莫德雷。我是妮可．布萊伊莫。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그리고 모모는 모모고요. 변한 건 아무것도 없어요.","JPN":"そしてモモはモモです。何も変わっていませんよ。","ENG":"And you're Momo. Nothing about that has changed.","TWN":"而莫莫就是莫莫，什麼都沒有改變。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"정말... 그걸로 괜찮은 것이냐?","JPN":"本当に……それでいいのか？","ENG":"Are you sure... you're okay with that?","TWN":"真的……可以這樣嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 모르가나란 소녀도, 니콜이 누구인지 모르던 걸요?","JPN":"そのモルガナって子も、ニコルが誰なのか知らなかったんですよ？","ENG":"That girl Morgana didn't even know who Nicole was either.","TWN":"那個叫莫甘娜的孩子，也不知道妮可是誰啊？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"전생의 기억이니, 운명 같은 건 처음부터 중요하지 않았어요. 제가 데려오고 싶었던 사람은 처음부터 모모였으니까.","JPN":"前世の記憶とか運命とか、そんなものは最初からどうでもよかったんです。私が連れ戻したかったのは最初からモモでしたから。","ENG":"Memories of a past life, fate, things like that were never what mattered. The one I wanted to bring back from the start was you, Momo.","TWN":"既然只是前世的記憶，命運之類的東西從一開始就不重要。我想帶回來的人，從一開始就只有莫莫而已。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"정말로......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"보고 싶었도다. 니콜.","JPN":"会いたかったぞ、ニコル。","ENG":"I missed you, Nicole.","TWN":"我好想你啊，妮可。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"...저도요.","JPN":"……私もです。","ENG":"...I missed you too.","TWN":"……我也是。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이제 우리, 다신 헤어지지 말아요.","JPN":"これからはずっと一緒ですよ、私たち。","ENG":"Let's never leave each other's side from now on.","TWN":"以後就一直在一起吧，我們。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗.","JPN":"あっ。","ENG":"Ah.","TWN":"啊。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"다녀오셨어요?","JPN":"お帰りになってたんですか？","ENG":"You're back.","TWN":"你回來啦？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"...그래.","JPN":"……ええ。","ENG":"...Yes.","TWN":"……嗯。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"두 사람도, 먼 길 다녀오느라 고생 많았어.","JPN":"二人も、長旅お疲れさま。","ENG":"You two must have had a long journey as well. Good work making it back.","TWN":"你們兩個跑這麼遠也辛苦了。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"...이상으로, 도시관리국 별 정례보고를 마치겠습니다.","JPN":"……以上、各都市管理局の定期報告を終わります。","ENG":"...That concludes the regular regional report from the City Management.","TWN":"……以上是城市管理局本次的定期報告。"},"stage":{"bg":"OMEN_G1_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 다들 수고 많았네.","JPN":"ああ、皆ご苦労だった。","ENG":"Okay. Good job, everyone.","TWN":"好。大家都辛苦了。"},"stage":{"bg":"OMEN_G1_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"당분간은 모두들 재난 수복에 힘써주게나.","JPN":"今後も引き続き修復に力を尽くしてくれ。","ENG":"Please continue prioritizing the city's restoration efforts.","TWN":"今後也請繼續努力進行修復工作。"},"stage":{"bg":"OMEN_G1_02","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};